+        assert_eq!(a.len(), 2);
+        assert_eq!(a.values()[0], Scalar::Int64(1));
+
+        let b = &series_map["b"];
+        assert_eq!(b.name(), "b");
+        assert_eq!(b.values()[1], Scalar::Float64(4.0));
+    }
